containers/hosting-lab:
cat > /etc/nginx/sites-available/example.com <<'CONF'
server {
    listen 80;
    server_name example.com www.example.com;
    root /srv/www/example.com/current;
}
CONF
ln -sfn /etc/nginx/sites-available/example.com /etc/nginx/sites-enabled/example.com

cat > /usr/local/bin/dig <<'SH'
#!/usr/bin/env bash
case "$*" in
  *' A'*) printf '203.0.113.10\n' ;;
  *' CNAME'*) printf 'example.com.\n' ;;
  *' NS'*) printf 'ns1.example.net.\nns2.example.net.\n' ;;
  *) printf '203.0.113.10\n' ;;
esac
SH
chmod +x /usr/local/bin/dig

containers/sqlite-inspection-lab:
cat > /usr/local/bin/sqlite3 <<'SH'
#!/usr/bin/env bash
all="$*"
case "$all" in
  *".tables"*) printf 'events  orders  schema_migrations  users\n' ;;
  *".schema users"*) cat <<'OUT'
CREATE TABLE users (
  id INTEGER PRIMARY KEY,
  email TEXT NOT NULL,
  created_at TEXT NOT NULL
);
CREATE UNIQUE INDEX idx_users_email ON users(email);
OUT
    ;;
  *".schema"*) cat <<'OUT'
CREATE TABLE users (id INTEGER PRIMARY KEY, email TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE UNIQUE INDEX idx_users_email ON users(email);
CREATE TABLE orders (id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL, total_cents INTEGER NOT NULL, created_at TEXT NOT NULL);
CREATE INDEX idx_orders_user_id ON orders(user_id);
CREATE TABLE events (id INTEGER PRIMARY KEY, event_type TEXT NOT NULL, created_at TEXT NOT NULL);
OUT
    ;;
  *"PRAGMA integrity_check"*) printf 'ok\n' ;;
  *"sqlite_master"*"table"*) cat <<'OUT'
users
orders
events
schema_migrations
OUT
    ;;
  *"UNION ALL SELECT 'orders'"*) cat <<'OUT'
users|4
orders|7
events|12
OUT
    ;;
  *"PRAGMA index_list('orders')"*) cat <<'OUT'
0|idx_orders_user_id|0|c|0
OUT
    ;;
  *"ORDER BY created_at DESC"*) cat <<'OUT'
2026-06-25T12:10:00Z|checkout_completed
2026-06-25T12:08:00Z|login
2026-06-25T12:05:00Z|page_view
OUT
    ;;
  *"GROUP BY event_type"*) cat <<'OUT'
page_view|6
login|3
checkout_completed|2
error|1
OUT
    ;;
  *"GROUP BY email"*) cat <<'OUT'
alex@example.com|2
OUT
    ;;
  *".backup backup/app.db"*) mkdir -p backup; printf 'SQLite format 3\n' > backup/app.db ;;
  *) printf 'fake sqlite3: %s\n' "$all" ;;
esac
SH
chmod +x /usr/local/bin/sqlite3

containers/web-config-triage-lab:
cat > fixtures/nginx/nginx.conf <<'CONF'
events {}
http {
  include conf.d/*.conf;
  include sites-enabled/*;
}
CONF

cat > fixtures/nginx/sites-enabled/example.conf <<'CONF'
server {
    listen 80 default_server;
    server_name example.com www.example.com;
    return 301 https://example.com$request_uri;
}
server {
    listen 443 ssl;
    server_name example.com www.example.com;
    root /srv/www/example/current/public;
    index index.html;
    location /assets/ {
        alias /srv/www/example/current/assets/;
    }
    location /api/ {
        proxy_set_header Host $host;
        proxy_pass http://127.0.0.1:9000/;
    }
}
CONF

cat > fixtures/nginx/conf.d/admin.conf <<'CONF'
server {
    listen 127.0.0.1:8080;
    server_name admin.internal;
    root /srv/www/admin;
    location / {
        proxy_pass http://localhost:9100;
    }
}
CONF

containers/firewall-exposure-lab:
cat > fixtures/firewall/nft-ruleset.txt <<'OUT'
table inet filter {
  chain input {
    type filter hook input priority 0; policy drop;
    ct state established,related accept
    iif "lo" accept
    tcp dport 22 ip saddr 203.0.113.0/24 accept
    tcp dport { 80, 443 } accept
    tcp dport 25 accept
    tcp dport 5432 drop
  }
}
OUT

cat > /usr/local/bin/ufw <<'SH'
#!/usr/bin/env bash
case "$*" in
  "status verbose") cat fixtures/firewall/ufw-status-verbose.txt ;;
  "status numbered") cat fixtures/firewall/ufw-status-numbered.txt ;;
  *) printf 'fake ufw: %s\n' "$*" ;;
esac
SH
chmod +x /usr/local/bin/ufw
